@import '../../utils/focus-ring.css';

:host {
  display: inline-flex;
  flex: 0 0 auto;
  width: var(--dimension-size-400);
  height: var(--dimension-size-400);
  outline: none;
  --ds-button-unfilled-icon-fg: var(--color-foreground-secondary);
  --ds-button-unfilled-icon-fg-active: var(--color-foreground-primary);
  --ds-button-unfilled-icon-active-bg: var(--color-interaction-active);
  --ds-button-unfilled-icon-hover-bg: var(--color-interaction-hover);
  --ds-button-unfilled-icon-pressed-bg: var(--color-interaction-pressed);
  --ds-button-unfilled-icon-dot-ring: var(--color-background-secondary);
  --ds-button-unfilled-icon-border: var(--color-border-tertiary);
}

.button-icon {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  width: var(--dimension-size-400);
  height: var(--dimension-size-400);
  padding: var(--dimension-space-075);
  background: transparent;
  border: var(--dimension-stroke-width-012, 1px) solid transparent;
  border-radius: var(--dimension-radius-025);
  color: var(--ds-button-unfilled-icon-fg);
  cursor: pointer;
  box-sizing: border-box;
  -webkit-user-select: none;
  user-select: none;
  position: relative;
  overflow: hidden;
  transition: color var(--effect-motion-short-2);
}

.button-icon::before,
.button-icon::after {
  content: '';
  position: absolute;
  inset: 0;
  border-radius: inherit;
  background: transparent;
  pointer-events: none;
  transition: none;
  z-index: 1;
}

.button-icon::before {
  z-index: 0;
}

.button-icon--active-fill::before {
  background: var(--ds-button-unfilled-icon-active-bg);
}

.button-icon:hover:not(.button-icon--inactive)::after {
  background: var(--ds-button-unfilled-icon-hover-bg);
  transition: none;
}

.button-icon:active:not(.button-icon--inactive)::after {
  background: var(--ds-button-unfilled-icon-pressed-bg);
  transition: none;
}

.button-icon--active {
  color: var(--ds-button-unfilled-icon-fg-active);
}

.button-icon--bordered {
  border-color: var(--ds-button-unfilled-icon-border);
}

.button-icon--bordered::after {
  inset: var(--dimension-stroke-width-012, 1px);
}

.button-icon--bordered::before {
  inset: var(--dimension-stroke-width-012, 1px);
}

.button-icon--inactive {
  opacity: 0.5;
  cursor: not-allowed;
  pointer-events: none;
}

.button-icon--on-medium {
  --ds-button-unfilled-icon-active-bg: var(--color-interaction-on-medium-background-active);
  --ds-button-unfilled-icon-hover-bg: var(--color-interaction-on-medium-background-hover);
  --ds-button-unfilled-icon-pressed-bg: var(--color-interaction-on-medium-background-pressed);
  --ds-button-unfilled-icon-dot-ring: var(--color-background-medium-neutral);
  --ds-focus-ring-color: var(--color-interaction-on-medium-background-focus);
}

.button-icon--on-bold {
  --ds-button-unfilled-icon-fg: var(--color-foreground-on-bold-background-secondary);
  --ds-button-unfilled-icon-fg-active: var(--color-foreground-on-bold-background-primary);
  --ds-button-unfilled-icon-active-bg: var(--color-interaction-on-bold-background-active);
  --ds-button-unfilled-icon-hover-bg: var(--color-interaction-on-bold-background-hover);
  --ds-button-unfilled-icon-pressed-bg: var(--color-interaction-on-bold-background-pressed);
  --ds-button-unfilled-icon-dot-ring: var(--color-background-bold-neutral);
  --ds-focus-ring-color: var(--color-interaction-on-bold-background-focus);
}

.button-icon--on-strong {
  --ds-button-unfilled-icon-fg: var(--color-foreground-on-bold-background-secondary);
  --ds-button-unfilled-icon-fg-active: var(--color-foreground-on-bold-background-primary);
  --ds-button-unfilled-icon-active-bg: var(--color-interaction-on-strong-background-active);
  --ds-button-unfilled-icon-hover-bg: var(--color-interaction-on-strong-background-hover);
  --ds-button-unfilled-icon-pressed-bg: var(--color-interaction-on-strong-background-pressed);
  --ds-button-unfilled-icon-dot-ring: var(--color-background-strong-neutral);
  --ds-focus-ring-color: var(--color-interaction-on-strong-background-focus);
}

.button-icon--on-always-dark {
  --ds-button-unfilled-icon-fg: var(--color-always-dark-foreground-secondary);
  --ds-button-unfilled-icon-fg-active: var(--color-always-dark-foreground-primary);
  --ds-button-unfilled-icon-active-bg: var(--color-always-dark-interaction-active);
  --ds-button-unfilled-icon-hover-bg: var(--color-always-dark-interaction-hover);
  --ds-button-unfilled-icon-pressed-bg: var(--color-always-dark-interaction-pressed);
  --ds-button-unfilled-icon-dot-ring: var(--color-always-dark-background);
  --ds-focus-ring-color: var(--color-always-dark-interaction-focus);
}

.button-icon--on-navigation {
  --ds-button-unfilled-icon-fg: var(--color-navigation-foreground-secondary);
  --ds-button-unfilled-icon-fg-active: var(--color-navigation-foreground-primary);
  --ds-button-unfilled-icon-active-bg: var(--color-navigation-interaction-active);
  --ds-button-unfilled-icon-hover-bg: var(--color-navigation-interaction-hover);
  --ds-button-unfilled-icon-pressed-bg: var(--color-navigation-interaction-pressed);
  --ds-button-unfilled-icon-dot-ring: var(--color-navigation-background);
  --ds-focus-ring-color: var(--color-navigation-interaction-focus);
}

.button-icon__icon-wrap {
  position: relative;
  width: var(--dimension-iconography-md);
  height: var(--dimension-iconography-md);
  display: inline-flex;
  align-items: center;
  justify-content: center;
  flex-shrink: 0;
  z-index: 2;
}

.button-icon__dot {
  position: absolute;
  top: 0;
  right: 0;
  pointer-events: none;
}

import { Component, Element, Event, EventEmitter, h, Host, Method, Prop } from '@stencil/core';

export type ButtonUnfilledIconBackground =
  | 'faint'
  | 'medium'
  | 'bold'
  | 'strong'
  | 'always-dark'
  | 'navigation';

@Component({
  tag: 'ds-button-unfilled-icon',
  styleUrl: 'ButtonUnfilledIcon.css',
  scoped: true,
})
export class ButtonUnfilledIcon {
  @Element() el!: HTMLElement;

  /** Icon name passed to <ds-icon>. */
  @Prop() icon: string = '';

  /** Active/selected visual state. */
  @Prop() isActive: boolean = false;

  /** When active, render the active interaction fill. Shell chrome can disable this while keeping active icon colour. */
  @Prop() activeFill: boolean = true;

  /** Show a 1px tertiary border without changing the interaction model. */
  @Prop() hasBorder: boolean = false;

  /** Show a notification dot at the top-right of the icon zone. */
  @Prop() dot: boolean = false;

  /** Disables interaction. */
  @Prop() inactive: boolean = false;

  /** Native button type. */
  @Prop() type: 'button' | 'submit' | 'reset' = 'button';

  /** Parent surface context — adjusts hover/press/focus colours for coloured backgrounds. */
  @Prop() background: ButtonUnfilledIconBackground | undefined;

  @Prop({ attribute: 'aria-label' }) ariaLabel: string = 'action';
  @Prop() controls: string | undefined;
  @Prop() expanded: boolean | undefined;
  @Prop() haspopup: string | undefined;
  @Prop() pressed: boolean | undefined;

  /**
   * Native `tabindex` for roving keyboard groups in shell chrome.
   * Omit for the default button tab stop (`0`).
   */
  @Prop({ attribute: 'tab-index' }) focusTabIndex?: number;

  @Event() dsClick!: EventEmitter<MouseEvent>;
  @Event() dsChange!: EventEmitter<boolean>;

  private buttonEl: HTMLButtonElement | null = null;

  @Method()
  async setFocus() {
    this.buttonEl?.focus();
  }

  private handleClick = (event: MouseEvent) => {
    if (this.inactive) return;
    this.dsClick.emit(event);
    this.dsChange.emit(!this.isActive);
  };

  render() {
    const bg = this.background;

    const cls: Record<string, boolean> = {
      'button-icon': true,
      'ds-focus-ring-inset': true,
      'button-icon--active': this.isActive,
      'button-icon--active-fill': this.isActive && this.activeFill,
      'button-icon--bordered': this.hasBorder,
      'button-icon--inactive': this.inactive,
      'button-icon--on-medium': bg === 'medium',
      'button-icon--on-bold': bg === 'bold',
      'button-icon--on-strong': bg === 'strong',
      'button-icon--on-always-dark': bg === 'always-dark',
      'button-icon--on-navigation': bg === 'navigation',
    };

    return (
      <Host tabIndex={-1}>
        <button
          ref={el => {
            this.buttonEl = el ?? null;
          }}
          type={this.type}
          class={cls}
          disabled={this.inactive}
          tabIndex={this.focusTabIndex ?? 0}
          aria-label={this.ariaLabel}
          aria-controls={this.controls}
          aria-expanded={this.expanded === undefined ? undefined : String(this.expanded)}
          aria-haspopup={this.haspopup}
          aria-pressed={this.pressed === undefined ? undefined : String(this.pressed)}
          onClick={this.handleClick}
        >
          <span class="button-icon__icon-wrap">
            <ds-icon name={this.icon} size="md" color="inherit" />
            {this.dot && (
              <ds-badge
                class="button-icon__dot"
                variant="dot"
                background="var(--ds-button-unfilled-icon-dot-ring)"
                label=""
                aria-hidden="true"
              />
            )}
          </span>
        </button>
      </Host>
    );
  }
}
